mapper.select:
SELECT c.company_id, c.company_name, c.short_name, c.establish_date, c.asset_scale, c.fund_count, c.manager_count, COUNT(DISTINCT f.fund_id) AS imported_fund_count FROM fund_company c LEFT JOIN fund_info f ON f.company_id = c.company_id
AND c.company_name LIKE CONCAT('%', #{query.keyword}, '%')
AND EXISTS ( SELECT 1 FROM company_tag_relation ctr WHERE ctr.company_id = c.company_id AND ctr.tag_id IN
#{tagId}
)
GROUP BY c.company_id, c.company_name, c.short_name, c.establish_date, c.asset_scale, c.fund_count, c.manager_count ORDER BY imported_fund_count DESC, c.company_id DESC
